def ingest_document(
        db: Session,
        title: str,
        file_name: str,
        pages: list[dict],
        embedding_service: EmbeddingService,
) -> int:
    doc = Document(title=title, file_name=file_name)
    db.add(doc)
    db.flush()

    chunks = build_chunks_from_pages(pages)
    vectors = embedding_service.embed_texts([c["content"] for c in chunks])

    for c, vector in zip(chunks, vectors):
        chunk = DocumentChunk(
            document_id=doc.id,
            chunk_index=c["chunk_index"],
            content=c["content"],
            page_number=c["page_number"],
            meta=c["meta"],
        )
        db.add(chunk)
        db.flush()

        emb = ChunkEmbedding(chunk_id=chunk.id, embedding=vector)
        db.add(emb)

    db.commit()
    return doc.id


